  border-radius: 16px;
  padding: 32px 24px;
  width: 280px;
  text-align: center;
  border: 1px solid #e8e8e8;
  box-shadow: 0 2px 12px rgba(0,0,0,0.08);
  transition: all 0.3s ease;
}
