  holat = { ...holat, vazifalar: holat.vazifalar.filter(v => v.id !== id) };
  render();
};

const filterlangan = () => {
  const { vazifalar, filtr } = holat;
  return {
    hammasi: vazifalar,
    bajarilgan: vazifalar.filter(v => v.bajarildi),
    bajarilmagan: vazifalar.filter(v => !v.bajarildi)
  }[filtr] ?? vazifalar;
