  const yangi: Foydalanuvchi = { ...malumot, id: keyingiId++, yaratilgan: new Date() };
  foydalanuvchilar.push(yangi);
  return yangi;
}

function topibOl(id: number): Foydalanuvchi | undefined {
  return foydalanuvchilar.find(f => f.id === id);
}

function yangilash(id: number, ozgarishlar: Partial<Foydalanuvchi>): Foydalanuvchi | null {
  const indeks = foydalanuvchilar.findIndex(f => f.id === id);
  if (indeks === -1) return null;
  foydalanuvchilar[indeks] = { ...foydalanuvchilar[indeks], ...ozgarishlar };
  return foydalanuvchilar[indeks];
}

function ochir(id: number): boolean {
  const indeks = foydalanuvchilar.findIndex(f => f.id === id);
  if (indeks === -1) return false;
  foydalanuvchilar.splice(indeks, 1);
  return true;
}

