React 16.8 dan boshlab hooks qo'shildi — funksional komponentlarda holat (state) va hayot tsikli (lifecycle) boshqarish imkoni.

**useState — holat boshqarish**
```jsx
import { useState } from 'react';

function Hisoblagich() {
  const [son, setSon] = useState(0); // [holat, yangilovchi]
  const [ism, setIsm] = useState('');
  const [yuklanmoqda, setYuklanmoqda] = useState(false);

  return (
    <div>
      <p>Son: {son}</p>
      <button onClick={() => setSon(son + 1)}>+</button>
      <button onClick={() => setSon(prev => prev - 1)}>-</button>
      {/* Oldingi qiymatga asoslanib yangilash */}
      <button onClick={() => setSon(prev => prev * 2)}>x2</button>
    </div>
  );
}

// Ob'ekt holat
function Forma() {
  const [forma, setForma] = useState({ ism: '', email: '', parol: '' });

  const ozgartir = (maydon) => (e) => {
    setForma(old => ({ ...old, [maydon]: e.target.value }));
  };

  return (
    <form>
      <input value={forma.ism} onChange={ozgartir('ism')} />
      <input value={forma.email} onChange={ozgartir('email')} />
    </form>
  );
}
```

**useEffect — yon ta'sirlar (side effects)**
```jsx
import { useState, useEffect } from 'react';

function FoydalanuvchiProfil({ id }) {
  const [foydalanuvchi, setFoydalanuvchi] = useState(null);
  const [yuklanmoqda, setYuklanmoqda] = useState(true);

  useEffect(() => {
    // Componentga mount bo'lganda va id o'zgarganda ishlaydi
    setYuklanmoqda(true);
    fetch(`/api/users/${id}`)
      .then(r => r.json())
      .then(data => {
        setFoydalanuvchi(data);
        setYuklanmoqda(false);
      });

    // Cleanup funksiya (unmount da yoki id o'zgarishidan oldin)
    return () => {
      console.log('Tozalash bajarildi');
    };
  }, [id]); // Dependency array: faqat id o'zgarganda qayta ishlaydi

  // [] — faqat bir marta (componentDidMount)
  // [a, b] — a yoki b o'zgarganda
  // dependency yo'q — har render da (xavfli!)

  if (yuklanmoqda) return <p>Yuklanmoqda...</p>;
  return <div>{foydalanuvchi?.ism}</div>;
}

// Subscription va subscription bekor qilish
useEffect(() => {
  const subscription = websocket.subscribe(xabarlar => {
    setXabarlar(prev => [...prev, ...xabarlar]);
  });

  return () => subscription.unsubscribe(); // Cleanup!
}, []);

// Event listener
useEffect(() => {
  const handler = (e) => console.log(e.key);
  window.addEventListener('keydown', handler);
  return () => window.removeEventListener('keydown', handler);
}, []);
```

**useContext — global holat**
```jsx
import { createContext, useContext, useState } from 'react';

// 1. Context yaratish
const MavzuKontekst = createContext({
  mavzu: 'yorug',
  almashtir: () => {}
});

// 2. Provider — qiymat beruvchi
function MavzuProvider({ children }) {
  const [mavzu, setMavzu] = useState('yorug');

  const almashtir = () => {
    setMavzu(old => old === 'yorug' ? 'qorongʻi' : 'yorug');
  };

  return (
    <MavzuKontekst.Provider value={{ mavzu, almashtir }}>
