  return (
    <h1 style={{ color: mavzu === 'qorongʻi' ? 'white' : 'black' }}>
      SYNAPSE
    </h1>
  );
}

function MavzuTugma() {
  const { mavzu, almashtir } = useContext(MavzuKontekst);
  return (
    <button onClick={almashtir}>
      {mavzu === 'yorug' ? '🌙' : '☀️'}
    </button>
  );
}

// 4. Ilova
