const MavzuKontekst = createContext();

function MavzuProvider({ children }) {
  const [qorong, setQorong] = useState(false);
  return (
    <MavzuKontekst.Provider value={{ qorong, almashtir: () => setQorong(p => !p) }}>
      <div style={{ minHeight:'100vh', background: qorong?'#1a1a2e':'#f5f6fa', color: qorong?'white':'black', padding:20 }}>
        {children}
      </div>
    </MavzuKontekst.Provider>
  );
}

function useDebounce(qiymat, kechikish) {
  const [kechiktirilgan, setKechiktirilgan] = useState(qiymat);
  useEffect(() => {
    const vaqt = setTimeout(() => setKechiktirilgan(qiymat), kechikish);
    return () => clearTimeout(vaqt);
  }, [qiymat, kechikish]);
  return kechiktirilgan;
}

function Qidiruvchi() {
  const { qorong, almashtir } = useContext(MavzuKontekst);
  const [foydalanuvchilar, setFoydalanuvchilar] = useState([]);
  const [qidiruv, setQidiruv] = useState('');
  const [yuklanmoqda, setYuklanmoqda] = useState(true);
  const debouncedQidiruv = useDebounce(qidiruv, 300);

  useEffect(() => {
    fetch('https://jsonplaceholder.typicode.com/users')
      .then(r => r.json())
      .then(data => { setFoydalanuvchilar(data); setYuklanmoqda(false); });
  }, []);

  const filterlangan = foydalanuvchilar.filter(f =>
    f.name.toLowerCase().includes(debouncedQidiruv.toLowerCase()) ||
    f.email.toLowerCase().includes(debouncedQidiruv.toLowerCase())
  );

  return (
    <div style={{ maxWidth:600, margin:'0 auto' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20 }}>
        <h1>Foydalanuvchilar</h1>
        <button onClick={almashtir} style={{ padding:'8px 16px', borderRadius:8, cursor:'pointer' }}>
          {qorong ? '☀️ Yorug' : '🌙 Qorongʻi'}
        </button>
      </div>
      <input value={qidiruv} onChange={e => setQidiruv(e.target.value)}
        placeholder='Ism yoki email qidiring...'
        style={{ width:'100%', padding:12, borderRadius:8, border:'2px solid #ddd', fontSize:16, marginBottom:16, boxSizing:'border-box' }} />
      {yuklanmoqda ? <p>Yuklanmoqda...</p> :
        filterlangan.map(f => (
          <div key={f.id} style={{ padding:16, borderRadius:8, marginBottom:8, background: qorong?'#16213e':'white', boxShadow:'0 1px 4px rgba(0,0,0,0.1)' }}>
            <strong>{f.name}</strong>
            <p style={{ margin:'4px 0', fontSize:13, color: qorong?'#aaa':'#888' }}>{f.email} · {f.company.name}</p>
          </div>
        ))
      }
    </div>
  );
}

