import { useParams, useNavigate, useLocation, useSearchParams } from 'react-router-dom';

function KursDetay() {
  const { id } = useParams(); // URL parametrlar
  const [kurs, setKurs] = useState(null);

  useEffect(() => {
    fetch(`/api/kurslar/${id}`).then(r => r.json()).then(setKurs);
  }, [id]);

  if (!kurs) return <p>Yuklanmoqda...</p>;
  return <h1>{kurs.nom}</h1>;
}

function QidiruvNatijalar() {
  const [searchParams, setSearchParams] = useSearchParams();
  const qidiruv = searchParams.get('q') || '';

  return (
    <input
      value={qidiruv}
      onChange={e => setSearchParams({ q: e.target.value })}
    />
  );
}

function LoginSahifa() {
  const navigate = useNavigate();
  const location = useLocation();

  const kirish = async () => {
    await login();
    // Oldingi sahifaga qaytish (agar yo'q bo'lsa bosh sahifaga)
    const keyin = location.state?.from?.pathname || '/';
