// Barcha komponentlar bir faylda (demo uchun)
import { BrowserRouter, Routes, Route, NavLink, useParams, Link, Navigate } from 'react-router-dom';
import { lazy, Suspense } from 'react';

const kurslar = [
  { id: 1, nom: 'Python Asoslari', ustoz: 'Ali', davomiyligi: '8 hafta', haqida: 'Python dasturlash tilining asoslarini o\'rganing.' },
  { id: 2, nom: 'React Pro', ustoz: 'Vali', davomiyligi: '10 hafta', haqida: 'Modern React bilan professional dastur yarating.' },
  { id: 3, nom: 'TypeScript', ustoz: 'Sara', davomiyligi: '6 hafta', haqida: 'TypeScript bilan xavfsiz kod yozing.' }
];

const navStil = ({ isActive }) => ({
  padding: '8px 16px', textDecoration: 'none',
  background: isActive ? '#3498db' : 'transparent',
  color: isActive ? 'white' : '#333',
  borderRadius: 8
});

const BoshSahifa = () => <div style={{padding:40,textAlign:'center'}}><h1>🚀 SYNAPSE ga Xush Kelibsiz!</h1><p>Kelajak dasturchilarning platformasi.</p><Link to='/kurslar' style={{padding:'12px 24px',background:'#3498db',color:'white',borderRadius:8,textDecoration:'none'}}>Kurslarni Ko\'ring</Link></div>;

const KurslarSahifa = () => (
  <div style={{padding:20,maxWidth:700,margin:'0 auto'}}>
    <h2>Barcha Kurslar</h2>
    <div style={{display:'grid',gap:16}}>
      {kurslar.map(k => (
        <div key={k.id} style={{padding:20,background:'white',borderRadius:10,boxShadow:'0 2px 8px rgba(0,0,0,0.08)'}}>
          <h3 style={{margin:'0 0 8px'}}>{k.nom}</h3>
          <p style={{margin:'4px 0',color:'#888'}}>👨‍🏫 {k.ustoz} | ⏱ {k.davomiyligi}</p>
          <Link to={`/kurslar/${k.id}`} style={{color:'#3498db'}}>Batafsil →</Link>
        </div>
      ))}
    </div>
  </div>
);

const KursDetay = () => {
  const { id } = useParams();
  const kurs = kurslar.find(k => k.id === Number(id));
  if (!kurs) return <Navigate to='/404' />;
  return (
    <div style={{padding:40,maxWidth:600,margin:'0 auto'}}>
      <Link to='/kurslar' style={{color:'#3498db'}}>← Orqaga</Link>
      <h1 style={{margin:'16px 0 8px'}}>{kurs.nom}</h1>
      <p>👨‍🏫 {kurs.ustoz} | ⏱ {kurs.davomiyligi}</p>
      <p>{kurs.haqida}</p>
    </div>
  );
};

const Haqimizda = () => <div style={{padding:40}}><h2>Biz haqimizda</h2><p>SYNAPSE — 2024 yilda tashkil etilgan.</p></div>;
const TopilmadI = () => <div style={{padding:40,textAlign:'center'}}><h2>404 — Sahifa Topilmadi</h2><Link to='/'>Bosh sahifaga qaytish</Link></div>;

export default function Ilova() {
  return (
    <BrowserRouter>
      <nav style={{display:'flex',gap:8,padding:'12px 20px',background:'#f8f9fa',borderBottom:'1px solid #eee'}}>
        <NavLink to='/' style={navStil}>Bosh Sahifa</NavLink>
        <NavLink to='/kurslar' style={navStil}>Kurslar</NavLink>
        <NavLink to='/haqimizda' style={navStil}>Haqimizda</NavLink>
      </nav>
      <Suspense fallback={<div style={{padding:40,textAlign:'center'}}>⏳ Yuklanmoqda...</div>}>
        <Routes>
          <Route path='/' element={<BoshSahifa />} />
          <Route path='/kurslar' element={<KurslarSahifa />} />
          <Route path='/kurslar/:id' element={<KursDetay />} />
          <Route path='/haqimizda' element={<Haqimizda />} />
          <Route path='*' element={<TopilmadI />} />
        </Routes>
      </Suspense>
    </BrowserRouter>
  );
}

