**Route Handlers (API)**
```typescript
// app/api/kurslar/route.ts
import { NextRequest, NextResponse } from 'next/server';

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const kategoriya = searchParams.get('kategoriya');

  const kurslar = await getKurslarDB(kategoriya);

  return NextResponse.json(kurslar);
}

export async function POST(request: NextRequest) {
  const body = await request.json();
  const yangi = await kursYaratDB(body);
  return NextResponse.json(yangi, { status: 201 });
}
```

