// LoginForm.jsx
import { useState } from 'react';
export default function LoginForm({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !password) {
      setError('Email va parol kiritish majburiy');
      return;
    }
    setError('');
    onLogin({ email, password });
  };
  return (
    <form onSubmit={handleSubmit}>
      {error && <p role="alert">{error}</p>}
      <label htmlFor="email">Email</label>
      <input id="email" value={email} onChange={e => setEmail(e.target.value)} />
      <label htmlFor="password">Parol</label>
      <input id="password" type="password" value={password} onChange={e => setPassword(e.target.value)} />
      <button type="submit">Kirish</button>
    </form>
  );
}

// LoginForm.test.jsx
test("bo'sh submit xato ko'rsatadi", async () => {
  const user = userEvent.setup();
  render(<LoginForm onLogin={jest.fn()} />);
  await user.click(screen.getByRole('button', { name: 'Kirish' }));
  expect(screen.getByRole('alert')).toHaveTextContent('Email va parol kiritish majburiy');
});

test("to'g'ri ma'lumot bilan onLogin chaqiriladi", async () => {
  const user = userEvent.setup();
  const mockLogin = jest.fn();
  render(<LoginForm onLogin={mockLogin} />);
  await user.type(screen.getByLabelText('Email'), 'test@test.com');
  await user.type(screen.getByLabelText('Parol'), 'parol123');
  await user.click(screen.getByRole('button'));
  expect(mockLogin).toHaveBeenCalledWith({ email: 'test@test.com', password: 'parol123' });
});

