**JavaScript optimizatsiya:**
```javascript
// 1. Debounce — scroll/resize hodisalari
function debounce(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

window.addEventListener('resize', debounce(() => {
  console.log('Resize tugadi');
}, 300));

// 2. Throttle — qidiruv
function throttle(fn, limit) {
  let inThrottle;
  return function(...args) {
    if (!inThrottle) {
      fn.apply(this, args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

// 3. Virtual list — ko'p element
// react-window yoki react-virtual ishlatish
