  <nav aria-label="Asosiy navigatsiya">
    <ul>
      <li><a href="/">Bosh sahifa</a></li>
      <li><a href="/haqida">Haqida</a></li>
    </ul>
  </nav>
</header>
<main id="main-content">
  <h1>Sahifa sarlavhasi</h1>
  <article>...</article>
</main>
<footer>...</footer>
