WebSocket — brauzer va server o'rtasida doimiy ikki tomonlama ulanish protokoli. HTTP'dan farqli o'laroq, WebSocket'da har so'rov uchun yangi ulanish ochilmaydi — bir ulanish doim ochiq qoladi.

**HTTP vs WebSocket:**
```
HTTP (Polling):
Client: So'rov yuboradi
Server: Javob beradi (ulanish yopiladi)
Client: 2 soniyadan so'ng yana so'rov (long polling)

WebSocket:
Client ←→ Server: Doimiy ochiq kanal
Server: Xohlagan vaqt xabar yuboradi
Client: Xohlagan vaqt xabar yuboradi
```

**Qachon WebSocket kerak:**
- Chat ilova
- Real-time bildirishnomalar
- Jonli sport natijalari
- Multiplayer o'yinlar
- Hamkorlikda hujjat tahrirlash (Google Docs)
- Fond birjasi ma'lumotlari
- Jonli monitoring dashboard

**Browser WebSocket API:**
```javascript
// Ulanish
const ws = new WebSocket('wss://api.example.com/ws');
// ws:// — oddiy, wss:// — xavfsiz (HTTPS kabi)

// Hodisalar
ws.onopen = (event) => {
  console.log('Ulandi!', ws.readyState); // 1 = OPEN
  ws.send(JSON.stringify({ type: 'join', room: 'general' }));
};

ws.onmessage = (event) => {
  const data = JSON.parse(event.data);
  console.log('Xabar keldi:', data);
  handleMessage(data);
};

ws.onerror = (error) => {
  console.error('WebSocket xato:', error);
};

ws.onclose = (event) => {
  console.log('Ulanish uzildi:', event.code, event.reason);
  // Qayta ulanish
  if (event.code !== 1000) { // 1000 = normal yopilish
    setTimeout(reconnect, 3000);
  }
};

// Xabar yuborish
function sendMessage(text) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify({
      type: 'message',
      text,
      timestamp: Date.now(),
    }));
  }
}

// Yopish
function disconnect() {
  ws.close(1000, 'Foydalanuvchi chiqdi');
}
```

**ReadyState qiymatlari:**
```javascript
WebSocket.CONNECTING = 0  // Ulanmoqda
WebSocket.OPEN       = 1  // Ulandi
WebSocket.CLOSING    = 2  // Yopilmoqda  
WebSocket.CLOSED     = 3  // Yopildi
```

**Avtomatik qayta ulanish bilan WebSocket klassi:**
```javascript
class ReconnectingWebSocket {
  constructor(url, options = {}) {
    this.url = url;
    this.maxRetries = options.maxRetries || 5;
    this.retryDelay = options.retryDelay || 2000;
    this.retries = 0;
    this.listeners = {};
    this.connect();
  }

  connect() {
    this.ws = new WebSocket(this.url);

    this.ws.onopen = (e) => {
      this.retries = 0;
      this.emit('open', e);
    };

    this.ws.onmessage = (e) => {
      try {
        this.emit('message', JSON.parse(e.data));
      } catch {
        this.emit('message', e.data);
      }
    };

    this.ws.onclose = (e) => {
      this.emit('close', e);
      if (this.retries < this.maxRetries) {
        this.retries++;
        console.log(`Qayta ulanish (${this.retries}/${this.maxRetries})...`);
        setTimeout(() => this.connect(), this.retryDelay * this.retries);
      }
    };

    this.ws.onerror = (e) => this.emit('error', e);
  }

  send(data) {
    if (this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(typeof data === 'string' ? data : JSON.stringify(data));
    }
  }

  on(event, callback) {
    if (!this.listeners[event]) this.listeners[event] = [];
    this.listeners[event].push(callback);
  }

  emit(event, data) {
    (this.listeners[event] || []).forEach(cb => cb(data));
  }

  close() {
    this.maxRetries = 0;
    this.ws.close(1000);
  }
}

// Ishlatish
const socket = new ReconnectingWebSocket('wss://api.example.com/ws');
socket.on('message', (data) => handleMessage(data));
socket.send({ type: 'ping' });
```

**React'da WebSocket (Custom Hook):**
```javascript
// hooks/useWebSocket.js
import { useState, useEffect, useRef, useCallback } from 'react';

export function useWebSocket(url) {
  const [messages, setMessages] = useState([]);
  const [status, setStatus] = useState('connecting');
  const wsRef = useRef(null);

  useEffect(() => {
    wsRef.current = new WebSocket(url);
    const ws = wsRef.current;

    ws.onopen = () => setStatus('connected');
    ws.onclose = () => setStatus('disconnected');
    ws.onerror = () => setStatus('error');
    ws.onmessage = (e) => {
      setMessages(prev => [...prev, JSON.parse(e.data)]);
    };

    return () => ws.close(1000);
  }, [url]);

  const sendMessage = useCallback((data) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(data));
    }
  }, []);

  return { messages, status, sendMessage };
}

// Ishlatish
function ChatRoom({ roomId }) {
  const { messages, status, sendMessage } = useWebSocket(
    `wss://api.example.com/chat/${roomId}`
  );

  return (
    <div>
      <p>Holat: {status}</p>
      {messages.map((msg, i) => <p key={i}>{msg.text}</p>)}
      <button onClick={() => sendMessage({ text: 'Salom!' })}>Yuborish</button>
    </div>
  );
}
```

