**Komponent kutubxonasi:**

```javascript
// Button komponenti — React
function Button({ 
  variant = 'primary', 
  size = 'md', 
  disabled = false, 
  loading = false,
  children,
  onClick 
}) {
  const classes = [
    'btn',
    `btn--${variant}`,  // primary, secondary, ghost, danger
    `btn--${size}`,     // sm, md, lg
    disabled && 'btn--disabled',
    loading && 'btn--loading'
  ].filter(Boolean).join(' ');

  return (
    <button 
      className={classes}
      disabled={disabled || loading}
      onClick={onClick}
    >
      {loading && <Spinner size="sm" />}
      {children}
    </button>
  );
}
```

