Web animatsiyalari foydalanuvchi tajribasini (UX) sezilarli yaxshilaydi. Ikki asosiy professional kutubxona: GSAP (vanilla JS uchun) va Framer Motion (React uchun).

**GSAP (GreenSock Animation Platform)** — eng kuchli JS animatsiya kutubxonasi:

```javascript
// O'rnatish
// npm install gsap
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { TextPlugin } from 'gsap/TextPlugin';

gsap.registerPlugin(ScrollTrigger, TextPlugin);

// Asosiy animatsiya
gsap.to('.hero-title', {
  duration: 1,
  opacity: 1,
  y: 0,
  ease: 'power3.out'
});

// Timeline — ketma-ket animatsiyalar
const tl = gsap.timeline({ defaults: { ease: 'power2.out', duration: 0.8 } });
tl
  .from('.logo', { opacity: 0, x: -50 })
  .from('.nav-items', { opacity: 0, y: -20, stagger: 0.1 }, '-=0.4')
  .from('.hero-text', { opacity: 0, y: 60 }, '-=0.3')
  .from('.hero-btn', { opacity: 0, scale: 0.8 }, '-=0.2');

// ScrollTrigger — scroll animatsiyalari
gsap.from('.feature-card', {
  scrollTrigger: {
    trigger: '.features-section',
    start: 'top 80%',
    end: 'bottom 20%',
    toggleActions: 'play none none reverse'
  },
  opacity: 0,
  y: 80,
  stagger: 0.2,
  duration: 0.8
});

// Parallax effekti
gsap.to('.background-image', {
  scrollTrigger: {
    trigger: '.hero',
    start: 'top top',
    end: 'bottom top',
    scrub: true
  },
  y: '30%'
});

// Hover animatsiyasi
const cards = document.querySelectorAll('.card');
cards.forEach(card => {
  card.addEventListener('mouseenter', () => {
    gsap.to(card, { scale: 1.03, boxShadow: '0 20px 40px rgba(0,0,0,0.15)', duration: 0.3 });
  });
  card.addEventListener('mouseleave', () => {
    gsap.to(card, { scale: 1, boxShadow: '0 4px 6px rgba(0,0,0,0.07)', duration: 0.3 });
  });
});
```

**Framer Motion** — React uchun deklarativ animatsiya:

```jsx
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';

// Asosiy animatsiya
function AnimatedCard({ children }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, ease: 'easeOut' }}
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
    >
      {children}
    </motion.div>
  );
}

// Ro'yxat animatsiyasi (stagger)
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.1, delayChildren: 0.2 }
  }
};
const itemVariants = {
  hidden: { opacity: 0, x: -20 },
  visible: { opacity: 1, x: 0 }
};

function List({ items }) {
  return (
    <motion.ul variants={containerVariants} initial="hidden" animate="visible">
      {items.map(item => (
        <motion.li key={item.id} variants={itemVariants}>{item.name}</motion.li>
      ))}
    </motion.ul>
  );
}

// Page transitions
function PageWrapper({ children }) {
  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={location.pathname}
        initial={{ opacity: 0, x: 100 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: -100 }}
        transition={{ duration: 0.3 }}
      >
        {children}
      </motion.div>
    </AnimatePresence>
  );
}

// Scroll animatsiyasi
function ScrollSection() {
  const { scrollYProgress } = useScroll();
  const scale = useTransform(scrollYProgress, [0, 1], [0.8, 1]);

  return (
    <motion.div style={{ scale }}>
      Scroll qiling...
    </motion.div>
  );
}
```

**Muhim eslatma:** `prefers-reduced-motion` media query'ni hurmat qiling:
```css
@media (prefers-reduced-motion: reduce) {
  *, ::before, ::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}
```

GSAP'da: `gsap.matchMedia()` orqali ham amalga oshiriladi.

