nazariya:
Katta React ilovalarida komponentlar o'rtasida ma'lumotlarni ulashish murakkablashib ketadi. State management kutubxonalari bu muammoni hal qiladi.

**Redux Toolkit (RTK)** — Redux'ning zamonaviy, soddalashtirilgan versiyasi:

```javascript
// npm install @reduxjs/toolkit react-redux

// store/authSlice.js — slice yaratish
import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';

// Async action
export const loginUser = createAsyncThunk(
  'auth/login',
  async ({ email, password }, { rejectWithValue }) => {
    try {
      const res = await fetch('/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });
      if (!res.ok) throw new Error('Login failed');
      return await res.json();
    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

const authSlice = createSlice({
  name: 'auth',
  initialState: {
    user: null,
    token: null,
    status: 'idle', // idle | loading | succeeded | failed
    error: null
  },
  reducers: {
    logout(state) {
      state.user = null;
      state.token = null;
    },
    updateProfile(state, action) {
      state.user = { ...state.user, ...action.payload };
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(loginUser.pending, (state) => { state.status = 'loading'; })
      .addCase(loginUser.fulfilled, (state, action) => {
        state.status = 'succeeded';
        state.user = action.payload.user;
        state.token = action.payload.token;
      })
      .addCase(loginUser.rejected, (state, action) => {
        state.status = 'failed';
        state.error = action.payload;
      });
  }
});

export const { logout, updateProfile } = authSlice.actions;
export default authSlice.reducer;

// Selectors
export const selectUser = state => state.auth.user;
export const selectIsLoggedIn = state => !!state.auth.token;

// store/index.js
import { configureStore } from '@reduxjs/toolkit';
import authReducer from './authSlice';
import coursesReducer from './coursesSlice';

export const store = configureStore({
  reducer: {
    auth: authReducer,
    courses: coursesReducer
  }
});

// main.jsx
import { Provider } from 'react-redux';
root.render(
  <Provider store={store}>
    <App />
  </Provider>
);

// Component ichida ishlatish
import { useSelector, useDispatch } from 'react-redux';

function Header() {
  const user = useSelector(selectUser);
  const isLoggedIn = useSelector(selectIsLoggedIn);
  const dispatch = useDispatch();

  return (
    <header>
      {isLoggedIn ? (
        <>
          <span>{user.name}</span>
          <button onClick={() => dispatch(logout())}>Chiqish</button>
        </>
      ) : <LoginButton />}
    </header>
  );
}
```

**Zustand** — oddiy, engil state management:

```javascript
// npm install zustand

// store/useAppStore.js
import { create } from 'zustand';
import { persist, devtools } from 'zustand/middleware';

export const useAuthStore = create(
  devtools(
    persist(
      (set, get) => ({
        user: null,
        token: null,
        xp: 0,
        streak: 0,

        login: async (email, password) => {
          const res = await fetch('/api/login', {
            method: 'POST',
            body: JSON.stringify({ email, password }),
            headers: { 'Content-Type': 'application/json' }
          });
          const data = await res.json();
          set({ user: data.user, token: data.token });
        },

        logout: () => set({ user: null, token: null }),

        addXP: (amount) => set(state => ({ xp: state.xp + amount })),

        incrementStreak: () => set(state => ({ streak: state.streak + 1 })),

        // Computed value (getter)
        getLevel: () => {
          const xp = get().xp;
          return Math.floor(xp / 100) + 1;
        }
      }),
      { name: 'synapse-auth' } // localStorage key
    )
  )
);

// Component ichida
function Profile() {
  const { user, xp, logout, getLevel } = useAuthStore();

  return (
    <div>
      <h2>{user?.name}</h2>
      <p>XP: {xp} | Level: {getLevel()}</p>
      <button onClick={logout}>Chiqish</button>
    </div>
  );
}

// Faqat kerakli qismni subscribe qilish (optimization)
const xp = useAuthStore(state => state.xp); // faqat xp o'zgarganda re-render
```

**Qachon qaysi birini ishlatish kerak?**
- **Redux Toolkit**: Katta jamoa, murakkab state, DevTools muhim bo'lganda
- **Zustand**: Kichik-o'rta loyiha, tez boshlash, oddiylik muhim bo'lganda
- **Context API**: Faqat oddiy, kam o'zgaradigan state uchun (theme, locale)

