// store/useSynapseStore.js
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useSynapseStore = create(
  persist(
    (set, get) => ({
      user: null,
      xp: 0,
      courses: {},
      setUser: (user) => set({ user }),
      addXP: (amount) => set(state => ({ xp: state.xp + amount })),
      completeLesson: (courseId, lessonId) => set(state => {
        const course = state.courses[courseId] || { completedLessons: [] };
        if (course.completedLessons.includes(lessonId)) return state;
        return {
          courses: {
            ...state.courses,
            [courseId]: { completedLessons: [...course.completedLessons, lessonId] }
          }
        };
      }),
      getLevel: () => Math.floor(get().xp / 200) + 1,
      getCourseProgress: (courseId, totalLessons) => {
        const completed = get().courses[courseId]?.completedLessons.length || 0;
        return Math.round((completed / totalLessons) * 100);
      }
    }),
    { name: 'synapse-store' }
  )
);

// XPBar.jsx
export function XPBar() {
  const xp = useSynapseStore(s => s.xp);
  const getLevel = useSynapseStore(s => s.getLevel);
  const level = getLevel();
  const progress = xp % 200;
  return (
    <div className="xp-bar">
      <span>Level {level}</span>
      <div className="bar"><div style={{ width: `${(progress/200)*100}%` }} /></div>
      <span>{xp} XP</span>
    </div>
  );
}

nazariya:
Micro Frontend — katta frontend ilovalarni kichik, mustaqil deploylanuvchi qismlarga bo'lish arxitekturasi. Micro services'ning frontend uchun ekvivalenti.

**Muammo:** Bitta katta monolitik frontend — 50+ dasturchi bitta repo'da ishlaydi, deploy ogʻirlashadi, texnologiyalarni yangilash qiyin.

**Yechim:** Har bir team o'z mini-ilovasini mustaqil develop va deploy qiladi, shell app ularni birlashtiradi.

```
Shell App (host)
├── Header MFE (team-platform)
├── Auth MFE (team-auth) 
├── Courses MFE (team-courses)  ← React 18
├── Payment MFE (team-payment) ← Vue 3
└── Dashboard MFE (team-analytics) ← React 18
```

**Webpack Module Federation** — eng keng tarqalgan yechim:

```javascript
// courses-app/webpack.config.js (remote)
const { ModuleFederationPlugin } = require('webpack').container;

module.exports = {
  plugins: [
    new ModuleFederationPlugin({
      name: 'courses',          // bu remote'ning nomi
      filename: 'remoteEntry.js', // expose qilinadigan entry fayl
      exposes: {
        './CourseList': './src/components/CourseList',
        './CourseDetail': './src/components/CourseDetail',
        './useCourses': './src/hooks/useCourses'
      },
      shared: {
        react: { singleton: true, requiredVersion: '^18.0.0' },
        'react-dom': { singleton: true, requiredVersion: '^18.0.0' }
      }
    })
  ]
};

// shell-app/webpack.config.js (host)
new ModuleFederationPlugin({
  name: 'shell',
  remotes: {
    courses: 'courses@http://localhost:3001/remoteEntry.js',
    auth: 'auth@http://localhost:3002/remoteEntry.js',
    // Production da:
    // courses: `courses@${process.env.COURSES_URL}/remoteEntry.js`
  },
  shared: {
    react: { singleton: true },
    'react-dom': { singleton: true }
  }
})

// Shell app ichida remote komponent ishlatish
import React, { Suspense, lazy } from 'react';
const CourseList = lazy(() => import('courses/CourseList'));

function App() {
  return (
    <div>
      <Suspense fallback={<Loading />}>
        <CourseList />
      </Suspense>
    </div>
  );
}
```

