// assembly/index.ts
export function calculateXP(lessons: i32, streak: i32, difficulty: i32): i32 {
  const base: i32 = lessons * 10;
  const streakBonus: i32 = streak > 7 ? streak * 4 : streak * 2;
  const diffMultiplier: i32 = difficulty === 3 ? 200 : difficulty === 2 ? 150 : 100;
  return (base + streakBonus) * diffMultiplier / 100;
}

export function getLevel(totalXP: i32): i32 {
  return totalXP / 200 + 1;
}

// index.js
async function main() {
  const response = await fetch('build/module.wasm');
  const bytes = await response.arrayBuffer();
  const { instance } = await WebAssembly.instantiate(bytes);
  const { calculateXP, getLevel } = instance.exports;

  const xp = calculateXP(5, 10, 2);
  const level = getLevel(xp);
  console.log(`5 dars, 10 kun streak, medium: ${xp} XP, Level ${level}`);
  // Output: 5 dars, 10 kun streak, medium: 130 XP, Level 1
}
main();

