// animations.js
gsap.registerPlugin(ScrollTrigger);

function initAnimations() {
  // Hero entrance
  const heroTl = gsap.timeline({ delay: 0.2 });
  heroTl
    .from('.hero-badge', { opacity: 0, y: 20, duration: 0.6 })
    .from('.hero-title', { opacity: 0, y: 50, duration: 0.8, ease: 'power3.out' }, '-=0.2')
    .from('.hero-description', { opacity: 0, y: 30, duration: 0.7 }, '-=0.4')
    .from('.hero-actions', { opacity: 0, y: 20, duration: 0.6 }, '-=0.3')
    .from('.stat', { opacity: 0, y: 20, stagger: 0.15, duration: 0.5 }, '-=0.2');

  // Counter animation
  document.querySelectorAll('.stat-num').forEach(el => {
    const target = parseInt(el.textContent);
    if (!isNaN(target)) {
      gsap.from({ val: 0 }, {
        val: target,
        duration: 2,
        scrollTrigger: { trigger: el, start: 'top 80%', once: true },
        onUpdate() { el.textContent = Math.round(this.targets()[0].val).toLocaleString() + '+'; }
      });
    }
  });

  // Courses scroll
  gsap.from('.course-card', {
    scrollTrigger: { trigger: '.courses-grid', start: 'top 75%' },
    opacity: 0, y: 60, stagger: 0.12, duration: 0.7, ease: 'back.out(1.4)'
  });
}

document.addEventListener('DOMContentLoaded', initAnimations);
