Social media ilovalar real vaqtda yangilanuvchi ma'lumotlar talab qiladi: yangi postlar, like'lar, izohlar darhol ko'rinishi kerak. WebSocket — bu server va client o'rtasida doimiy ikki tomonlama ulanish protokoli.

**WebSocket asoslari**
```js
// Server (Node.js + ws)
const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
  console.log('Yangi ulanish');

  ws.on('message', (data) => {
    const msg = JSON.parse(data);
    // Barcha ulanishlarga broadcast
    wss.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(JSON.stringify(msg));
      }
    });
  });

  ws.on('close', () => console.log('Ulanish uzildi'));
});
```

**React'da Custom WebSocket Hook**
```jsx
import { useEffect, useRef, useState, useCallback } from 'react';

function useWebSocket(url) {
  const ws = useRef(null);
  const [messages, setMessages] = useState([]);
  const [status, setStatus] = useState('connecting');

  useEffect(() => {
    ws.current = new WebSocket(url);

    ws.current.onopen = () => setStatus('connected');
    ws.current.onclose = () => setStatus('disconnected');
    ws.current.onerror = () => setStatus('error');
    ws.current.onmessage = (event) => {
      const data = JSON.parse(event.data);
      setMessages(prev => [data, ...prev].slice(0, 100)); // max 100 xabar
    };

    return () => ws.current?.close();
  }, [url]);

  const send = useCallback((data) => {
    if (ws.current?.readyState === WebSocket.OPEN) {
      ws.current.send(JSON.stringify(data));
    }
  }, []);

  return { messages, status, send };
}
```

